#### Part (b) тАФ Model Solution (7 marks)

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class SimpleCalculator extends JFrame implements ActionListener {
    JTextField txtNum1, txtNum2;
    JButton btnAdd, btnSub, btnMul, btnDiv, btnClear;
    JLabel lblResult;

    public SimpleCalculator() {
        setTitle("Simple Calculator");
        setSize(350, 200);
        setDefaultCloseOperation(EXIT_ON_CLOSE);
        setLayout(new GridLayout(4, 2, 5, 5));

        txtNum1 = new JTextField();
        txtNum2 = new JTextField();

        btnAdd   = new JButton("+");
        btnSub   = new JButton("-");
        btnMul   = new JButton("*");
        btnDiv   = new JButton("/");
        btnClear = new JButton("Clear");

        lblResult = new JLabel("Result: ");
        lblResult.setHorizontalAlignment(SwingConstants.CENTER);

        btnAdd.addActionListener(this);
        btnSub.addActionListener(this);
        btnMul.addActionListener(this);
        btnDiv.addActionListener(this);
        btnClear.addActionListener(this);

        add(new JLabel("Number 1:"));
        add(txtNum1);
        add(new JLabel("Number 2:"));
        add(txtNum2);
        add(btnAdd);
        add(btnSub);
        add(btnMul);
        add(btnDiv);
        add(lblResult);
        add(btnClear);

        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        try {
            double a = Double.parseDouble(txtNum1.getText());
            double b = Double.parseDouble(txtNum2.getText());
            double r = 0;

            if (e.getSource() == btnAdd)      r = a + b;
            else if (e.getSource() == btnSub) r = a - b;
            else if (e.getSource() == btnMul) r = a * b;
            else if (e.getSource() == btnDiv) {
                if (b == 0) {
                    JOptionPane.showMessageDialog(this, "Cannot divide by zero",
                        "Error", JOptionPane.ERROR_MESSAGE);
                    return;
                }
                r = a / b;
            }
            lblResult.setText("Result: " + r);
        } catch (NumberFormatException ex) {
            JOptionPane.showMessageDialog(this, "Please enter valid numbers",
                "Input Error", JOptionPane.ERROR_MESSAGE);
        }

        if (e.getSource() == btnClear) {
            txtNum1.setText("");
            txtNum2.setText("");
            lblResult.setText("Result: ");
        }
    }

    public static void main(String[] args) {
        new SimpleCalculator();
    }
}
```

**Marking distribution (7 marks):**
- Correct component creation тАФ 2 marks
- Layout setup тАФ 1 mark
- Listener registration тАФ 1 mark
- Event-handling logic for 4 operations тАФ 2 marks
- Error handling (division by zero, parse exception) тАФ 1 mark

> [!WARNING]
> **Examiner's Pitfall Callout (Calculator Question):**
