```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class CountrySelector extends JFrame implements ActionListener {
    JList<String> countryList;
    JLabel displayLabel;
    JButton showButton;

    public CountrySelector() {
        setTitle("Country Selector");
        setSize(300, 250);
        setDefaultCloseOperation(EXIT_ON_CLOSE);
        setLayout(new FlowLayout());

        String[] countries = {"India", "USA", "UK", "Japan", "Germany"};
        countryList = new JList<>(countries);
        countryList.setSelectionMode(ListSelectionModel.SINGLE_SELECTION);
        countryList.setVisibleRowCount(3);

        JScrollPane scrollPane = new JScrollPane(countryList);

        displayLabel = new JLabel("Selected: ");
        showButton   = new JButton("Show");

        showButton.addActionListener(this);

        add(new JLabel("Choose a country:"));
        add(scrollPane);
        add(showButton);
        add(displayLabel);

        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getSource() == showButton) {
            String selected = countryList.getSelectedValue();
            if (selected == null) {
                JOptionPane.showMessageDialog(this, "Please select a country first",
                    "Warning", JOptionPane.WARNING_MESSAGE);
            } else {
                displayLabel.setText("Selected: " + selected);
            }
        }
    }

    public static void main(String[] args) {
        new CountrySelector();
    }
}
```

