### Model Solution for Q-A(b): 7 Marks тАФ Simple Calculator

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class Calculator extends JFrame {
    JTextField display;
    double num1 = 0, num2 = 0, result = 0;
    char operator;

    Calculator() {
        setTitle("Simple Calculator");
        setSize(300, 400);
        setLayout(new BorderLayout());
        setDefaultCloseOperation(EXIT_ON_CLOSE);

        display = new JTextField();
        display.setEditable(false);
        display.setHorizontalAlignment(JTextField.RIGHT);
        add(display, BorderLayout.NORTH);

        JPanel panel = new JPanel();
        panel.setLayout(new GridLayout(4, 4, 5, 5));

        String[] buttons = {
            "7", "8", "9", "/",
            "4", "5", "6", "*",
            "1", "2", "3", "-",
            "0", "C", "=", "+"
        };

        for (String text : buttons) {
            JButton btn = new JButton(text);
            panel.add(btn);

            btn.addActionListener(new ActionListener() {
                public void actionPerformed(ActionEvent e) {
                    String cmd = e.getActionCommand();

                    if (Character.isDigit(cmd.charAt(0))) {
                        display.setText(display.getText() + cmd);
                    } 
                    else if (cmd.equals("C")) {
                        display.setText("");
                        num1 = num2 = result = 0;
                    } 
                    else if (cmd.equals("=")) {
                        num2 = Double.parseDouble(display.getText());
                        switch (operator) {
                            case '+': result = num1 + num2; break;
                            case '-': result = num1 - num2; break;
                            case '*': result = num1 * num2; break;
                            case '/': result = num1 / num2; break;
                        }
                        display.setText(String.valueOf(result));
                    } 
                    else { // operator
                        num1 = Double.parseDouble(display.getText());
                        operator = cmd.charAt(0);
                        display.setText("");
                    }
                }
            });
        }

        add(panel, BorderLayout.CENTER);
        setVisible(true);
    }

    public static void main(String[] args) {
        new Calculator();
    }
}
```

**Explanation of Key Logic (for valuation):**
- `getActionCommand()` retrieves the button's text label.
- `Character.isDigit()` distinguishes numbers from operators.
- The `switch` block performs the arithmetic based on the stored `operator`.
- `setDefaultCloseOperation(EXIT_ON_CLOSE)` ensures the JVM terminates when the window closes.

