### 3.4.4 The `BorrowTransaction` Class

```java
import java.time.LocalDate;
import java.time.temporal.ChronoUnit;

public class BorrowTransaction {
    private String transactionId;
    private Book book;
    private User user;
    private LocalDate borrowDate;
    private LocalDate dueDate;
    private LocalDate returnDate;
    private double fine;

    public static final int    LOAN_PERIOD_DAYS = 14;
    public static final double FINE_PER_DAY     = 2.0;

    public BorrowTransaction(String transactionId, Book book, User user) {
        this.transactionId = transactionId;
        this.book          = book;
        this.user          = user;
        this.borrowDate    = LocalDate.now();
        this.dueDate       = borrowDate.plusDays(LOAN_PERIOD_DAYS);
        this.fine          = 0.0;
    }

    public double calculateFine() {
        if (returnDate == null) return 0.0;
        long daysBorrowed = ChronoUnit.DAYS.between(borrowDate, returnDate);
        long overdue      = Math.max(0, daysBorrowed - LOAN_PERIOD_DAYS);
        this.fine = overdue * FINE_PER_DAY;
        return fine;
    }

    public boolean isOverdue() {
        return returnDate == null
               && LocalDate.now().isAfter(dueDate);
    }

    public void closeTransaction() {
        this.returnDate = LocalDate.now();
        calculateFine();
    }

    public String getTransactionId() { return transactionId; }
    public Book   getBook()          { return book; }
    public User   getUser()          { return user; }
    public LocalDate getBorrowDate() { return borrowDate; }
    public LocalDate getDueDate()    { return dueDate; }
    public LocalDate getReturnDate() { return returnDate; }
    public double    getFine()       { return fine; }
}
```

### 3.4.5 The `Library` Class (Aggregation + Circulation Logic)

```java
import java.util.*;
import java.util.stream.Collectors;

public class Library {
    private List<Book> books;
    private List<User> users;
    private int transactionCounter = 1000;

    public Library() {
        this.books = new ArrayList<>();
        this.users = new ArrayList<>();
    }

    // -------- BOOK MANAGEMENT --------
    public void addBook(Book book)     { books.add(book); }
    public void removeBook(Book book)  { books.remove(book); }

    public Book searchByIsbn(String isbn) {
        return books.stream()
                    .filter(b -> b.getIsbn().equals(isbn))
                    .findFirst().orElse(null);
    }

    public List<Book> searchByTitle(String title) {
        return books.stream()
                    .filter(b -> b.getTitle().equalsIgnoreCase(title))
                    .collect(Collectors.toList());
    }

    public List<Book> searchByAuthor(String author) {
        return books.stream()
                    .filter(b -> b.getAuthor().equalsIgnoreCase(author))
                    .collect(Collectors.toList());
    }

    public List<Book> searchByGenre(String genre) {
        return books.stream()
                    .filter(b -> b.getGenre().equalsIgnoreCase(genre))
                    .collect(Collectors.toList());
    }

    // -------- USER MANAGEMENT --------
    public void registerUser(User user) { users.add(user); }

    public User searchUserById(String userId) {
        return users.stream()
                    .filter(u -> u.getUserId().equals(userId))
                    .findFirst().orElse(null);
    }

    public List<User> searchUserByName(String name) {
        return users.stream()
                    .filter(u -> u.getName().equalsIgnoreCase(name))
                    .collect(Collectors.toList());
    }

    // -------- CIRCULATION: ISSUE --------
    public BorrowTransaction issueBook(String isbn, String userId) {
        // Step 1: Locate the user
        User user = searchUserById(userId);
        if (user == null) {
            throw new IllegalArgumentException("User not found: " + userId);
        }

        // Step 2: Eligibility check
        if (user.getActiveLoanCount() >= 3) {
            throw new IllegalStateException("Loan limit exceeded for " + userId);
        }

        // Step 3: Locate & validate the book
        Book book = searchByIsbn(isbn);
        if (book == null) {
            throw new IllegalArgumentException("Book not found: " + isbn);
        }
        book.markBorrowed();   // throws IllegalStateException if not AVAILABLE

        // Step 4: Persist transaction
        String txnId = "TXN-" + LocalDate.now() + "-" + (++transactionCounter);
        BorrowTransaction txn = new BorrowTransaction(txnId, book, user);

        // Step 5: Update in-memory state
        user.addBorrowedBook(book);

        System.out.println("Issued: " + book + " to " + user.getName()
                           + " | Due: " + txn.getDueDate());
        return txn;
    }

    // -------- CIRCULATION: RETURN --------
    public double returnBook(String isbn, String userId) {
        User user = searchUserById(userId);
        Book book = searchByIsbn(isbn);
        if (user == null || book == null) {
            throw new IllegalArgumentException("Invalid ISBN or userId");
        }

        // Find the open transaction
        BorrowTransaction openTxn = findOpenTransaction(user, book);
        if (openTxn == null) {
            throw new IllegalStateException("No open transaction found.");
        }

        openTxn.closeTransaction();   // sets returnDate + computes fine
        book.markReturned();
        user.removeBorrowedBook(book);

        System.out.println("Returned: " + book + " | Fine: тВ╣" + openTxn.getFine());
        return openTxn.getFine();
    }

    private BorrowTransaction findOpenTransaction(User user, Book book) {
        // In-memory search; in production this would be a SQL query
        return user.borrowedBooks.contains(book)
               ? new BorrowTransaction("TEMP", book, user) // placeholder pattern
               : null;
    }
}
```

> [!IMPORTANT]
> The `findOpenTransaction` placeholder above is a **simplified academic version**. In a production KTU submission, you would maintain a `List<BorrowTransaction>` inside `Library` and iterate through it, querying `WHERE return_date IS NULL`. Examiners look for this distinction.

