    loanCheck -- No --> err3[Throw LoanLimitExceeded] --> stopA
    loanCheck -- Yes --> findBook{Book exists?}
    findBook -- No --> err4[Throw BookNotFound] --> stopA
    findBook -- Yes --> availCheck{Status equals AVAILABLE?}
    availCheck -- No --> err5[Throw BookUnavailable] --> stopA
    availCheck -- Yes --> mutate[Mark Book as BORROWED]
    mutate --> createTxn[Create BorrowTransaction object]
    createTxn --> setDates[Set borrowDate and dueDate]
    setDates --> addToUser[Add book to user.borrowedBooks]
    addToUser --> sqlPersist[Execute SQL UPDATE and INSERT]
    sqlPersist --> printReceipt[Print receipt with dueDate]
    printReceipt --> success([Return BorrowTransaction])
