);

CREATE TABLE TRANSACTIONS (
    transaction_id VARCHAR(20) PRIMARY KEY,
    isbn           VARCHAR(13) NOT NULL REFERENCES BOOKS(isbn),
    user_id        VARCHAR(10) NOT NULL REFERENCES USERS(user_id),
    borrow_date    DATE        NOT NULL,
    due_date       DATE        NOT NULL,
    return_date    DATE,
    fine_amount    DECIMAL(6,2) DEFAULT 0.00
);

CREATE INDEX idx_txn_user   ON TRANSACTIONS(user_id);
CREATE INDEX idx_txn_status ON TRANSACTIONS(return_date);
```

**3NF Justification (1 mark):** Every non-key column depends on the *whole* key, the *whole* key, and *nothing but the key*. The `TRANSACTIONS` table's `fine_amount` depends on `transaction_id` alone (no transitive dependency), satisfying 3NF.

